const fileContent = $input.first().json.stdout || '';
const project = $('Webhook').first().json.query.project;
const task = $('Webhook').first().json.query.task || '';

if (fileContent.trim() === 'FILE_NOT_FOUND') {
  return [{ json: { hasError: true, errorType: 'file_not_found', project } }];
}

if (!task.trim()) {
  return [{ json: { hasError: true, errorType: 'empty_task', project } }];
}

const newTodo = `- [ ] ${task.trim()}`;

let updated = fileContent;

// Find ## Backlog section and append after the existing todos
const backlogMatch = updated.match(/(## Backlog[\r\n]([\s\S]*?)(?=[\n]## |[\n]---|$))/m);

if (backlogMatch) {
  const backlogSection = backlogMatch[1];
  const commentEnd = backlogSection.lastIndexOf('-->');
  if (commentEnd !== -1) {
    // Insert after the comment
    const insertPos = updated.indexOf(backlogSection) + commentEnd + 3;
    updated = updated.slice(0, insertPos) + '\n' + newTodo + updated.slice(insertPos);
  } else {
    // Append at end of backlog section
    const insertPos = updated.indexOf(backlogSection) + backlogSection.length;
    updated = updated.slice(0, insertPos).trimEnd() + '\n' + newTodo + '\n' + updated.slice(insertPos);
  }
} else {
  // No backlog section — append at end
  updated = updated.trimEnd() + '\n\n## Backlog\n' + newTodo + '\n';
}

const base64Content = Buffer.from(updated).toString('base64');
return [{ json: { hasError: false, base64Content, project, task: task.trim() } }];
